import React from 'react';

const Header = () => {
  return (
    <header style={{ padding: '1.5rem', borderBottom: '1px solid #374151' }}>
      <h2 style={{ fontSize: '1.875rem', fontWeight: 'bold' }}>ML Analytics & API Gateway</h2>
      <p style={{ color: '#9ca3af' }}>Machine learning model performance, training analytics, and API endpoint monitoring</p>
    </header>
  );
};

export default Header;
